package ALUPkg;
    typedef enum logic [1:0] {
        PASS_A = 2'b00,
        ADD = 2'b01,
        SUB = 2'b10
    } ALUOpType;
endpackage: ALUPkg

module ALU_bind_error (
    input ALUPkg::ALUOpType ALUOp,
    input logic [31:0] A,
    input logic [31:0] B,
    output logic [31:0] out
);

import ALUPkg::*;

always @(*) begin
    case(ALUOp)
        PASS_A: out = A;
        ADD: out = A + B;
        SUB: out = A - B;
        default: out = A;
    endcase
end

endmodule: ALU_bind_error

module ALU_no_error (
    input ALUPkg::ALUOpType ALUOp,
    input logic [31:0] A,
    input logic [31:0] B,
    output logic [31:0] out
);

import ALUPkg::*;

ALUOpType do_nothing; //useless code
assign do_nothing = PASS_A; //useless code

always @(*) begin
    case(ALUOp)
        PASS_A: out = A;
        ADD: out = A + B;
        SUB: out = A - B;
        default: out = A;
    endcase
end

endmodule: ALU_no_error
